//   -> (icmp uge (add A, B), A)
// Both conditions check for unsigned overflow of the same add, so they're
// equivalent. Either one implies the other.
// Also handle commuted forms: ugt/ule and swapped operands.
static Value *simplifyAndOrOfICmpsWithAddOverflow(ICmpInst *LHS, ICmpInst *RHS,
                                                   bool IsAnd) {
  Value *LHS0 = LHS->getOperand(0), *RHS0 = RHS->getOperand(0);
  Value *LHS1 = LHS->getOperand(1), *RHS1 = RHS->getOperand(1);
  ICmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
  Value *A, *B;

  // Check if we have (add A, B) as one operand of both comparisons
  if (match(LHS0, m_Add(m_Value(A), m_Value(B)))) {
    // LHS: icmp pred (add A, B), X
    // For OR with ULT: overflow detection
    // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) -> (icmp ult (add A, B), A)
    if (!IsAnd && PredL == ICmpInst::ICMP_ULT && PredR == ICmpInst::ICMP_ULT) {
      if ((LHS1 == A && RHS1 == B) || (LHS1 == B && RHS1 == A))
        return LHS;
