    // For AND with UGE: no overflow detection
    // (icmp uge (add A, B), A) & (icmp uge (add A, B), B) -> (icmp uge (add A, B), A)
    if (IsAnd && PredL == ICmpInst::ICMP_UGE && PredR == ICmpInst::ICMP_UGE) {
      if ((LHS1 == A && RHS1 == B) || (LHS1 == B && RHS1 == A))
        return LHS;
    }
  }
  // Check if we have (add A, B) as the second operand of both comparisons
  // (icmp ugt A, (add A, B)) | (icmp ugt B, (add A, B)) -> (icmp ugt A, (add A, B))
  if (match(LHS1, m_Add(m_Value(A), m_Value(B)))) {
